With.Query:

				SELECT {{
							-Fields 
								-Dimension: Users 
									-Table: UsersCte
								-Dimension: UsersPointOfSale 
									-Table: UsersPointOfSaleCte
								-Dimension: PointsOfSale 
									-Table: PointsOfSaleCte
								-Dimension: Products 
									-Table: ProductsCte
								-Dimension:
									-Name:Calendar 
									-Table:CalendarCte 
									-WithPrimaryKey
								-WithComma
                		}}
                		SalesAnalysis.SalesQuantity, SalesAnalysis.SalesAmountTaxesIncluded, SalesAnalysis.SalesAmountTaxesExcluded,
                		SalesAnalysis.Refund
                	FROM Fact.SalesAnalysis
                	{{
                		-InnerJoin 
                			-Dimension: UsersPointOfSale 
                    			-IfRequest: Users
                    			-IfRequest: PointsOfSale 
                    			-Table: UsersPointOfSaleCte 
                			-Table: SalesAnalysis 
                			-On: UserPointOfSaleId-UserPointOfSaleId
                	}}
                	{{
                		-InnerJoin 
                			-Dimension: Users 
                				-Table: UsersCte
							-Table: UsersPointOfSaleCte
							-On:UserId-UserId
                	}}
                	{{
                		-InnerJoin 
                			-Dimension: PointsOfSale 
                				-Table:PointsOfSaleCte
							-Table:UsersPointOfSaleCte
							-On:PointOfSaleId-PointOfSaleId
                	}}
                	{{
                		-InnerJoin 
                			-Dimension: Products 
                				-Table: ProductsCte
							-Table: SalesAnalysis
							-On: ProductId-ProductId
                	}}
                	{{
                		-InnerJoin 
                			-Dimension: Calendar 
                				-Required
                				-Table: CalendarCte
							-Table:SalesAnalysis
							-On:Date-Date
                	}}
